solution_code:
#include <stdio.h>
#include <semaphore.h>
#include <fcntl.h>

int main(void) {
    sem_t *sem = sem_open("/kf_sem_named", O_CREAT | O_EXCL, 0644, 1);
    int val;

    sem_getvalue(sem, &val);
    printf("Initial: %d\n", val);

    sem_wait(sem);
    sem_getvalue(sem, &val);
    printf("After wait: %d\n", val);

    sem_post(sem);
    sem_getvalue(sem, &val);
    printf("After post: %d\n", val);

    sem_close(sem);
    sem_unlink("/kf_sem_named");
    return 0;
}

